);

// 使用 cron 表达式（每天凌晨 2 点）
scheduler.schedule(
  { name: "daily-report", cron: "0 2 * * *" },
  async () => {
    await generateDailyReport();
  }
);

// 注册时立即执行一次
scheduler.schedule(
  { name: "warmup", interval: 60_000, immediate: true },
  async () => {
    await warmupCache();
  }
);
```

