/** 连接池接口 */
interface ConnectionPool<T> {
  /** 获取连接（可能等待） */
  acquire(): Promise<T>;

  /** 释放连接回池 */
  release(conn: T): void;

  /** 销毁连接（从池中移除） */
  destroy(conn: T): void;

  /** 获取当前统计信息 */
  stats(): PoolStats;

  /** 排空并关闭连接池 */
  drain(): Promise<void>;

